export interface ExtractedFrame {
  id: string;
  timestamp: number;
  dataUrl: string;
  blurScore: number;
  hash: string;
  isStable: boolean;
  isUnique: boolean;
  aiFeedback?: string;
}

export interface ProcessingStats {
  totalFramesAnalyzed: number;
  duplicateCount: number;
  blurryCount: number;
  stableCount: number;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  EXTRACTING = 'EXTRACTING',
  ANALYZING = 'ANALYZING',
  AI_VALIDATING = 'AI_VALIDATING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { ExtractedFrame } from '../types';

/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  // Resize to 8x8 for hashing
  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  // Grayscale and average
  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r + g + b) / 3;
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  // Generate bit string
  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Calculates a simple blur score based on variance of intensity changes (simplified Laplacian).
 */
export function calculateBlurScore(canvas: HTMLCanvasElement): number {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return 0;

  const width = canvas.width;
  const height = canvas.height;
  // Use a small sample to speed up calculation
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  const values: number[] = [];

  // Very simplified: look at horizontal intensity shifts
  for (let i = 0; i < data.length; i += 40) { // Sample every 10th pixel roughly
    const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
    values.push(gray);
    mean += gray;
  }
  mean /= values.length;

  let variance = 0;
  for (const v of values) {
    variance += (v - mean) * (v - mean);
  }
  variance /= values.length;

  return variance; // Higher variance usually implies more sharp edges/detail
}

/**
 * Compares two hashes using Hamming Distance.
 */
export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExtractedFrame } from "../types";

export const validateFramesWithAI = async (frames: ExtractedFrame[]): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // We'll send the top N frames as images for review to save on tokens/latency
  const sampleSize = Math.min(frames.length, 5);
  const sampledFrames = frames.slice(0, sampleSize);

  const parts = sampledFrames.map(f => ({
    inlineData: {
      mimeType: "image/png",
      data: f.dataUrl.split(',')[1]
    }
  }));

  const prompt = `
    You are a professional video forensic specialist. 
    I have extracted these ${sampledFrames.length} frames from a video. 
    Please analyze them for:
    1. Visual quality (sharpness, no motion blur).
    2. Stability (no interlacing artifacts or compression blocks).
    3. Uniqueness (ensure they are not too similar).
    4. Composition (full visibility of the scene).

    Provide a brief expert validation summary for this set of screenshots.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [...parts, { text: prompt }] }
    });

    return [response.text || "AI analysis completed successfully."];
  } catch (error) {
    console.error("Gemini Error:", error);
    return ["AI validation failed but frames were processed manually."];
  }
};

import React from 'react';
import { ExtractedFrame } from '../types';

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  onDownload: (frame: ExtractedFrame) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ frames, onDownload }) => {
  if (frames.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-12 bg-gray-900/50 rounded-2xl border border-dashed border-gray-700">
        <svg className="w-16 h-16 text-gray-600 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
        <p className="text-gray-400">No frames extracted yet. Upload a video and start processing.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {frames.map((frame) => (
        <div key={frame.id} className="group relative bg-gray-800 rounded-xl overflow-hidden border border-gray-700 hover:border-blue-500/50 transition-all shadow-lg">
          <div className="aspect-video bg-black relative">
            <img 
              src={frame.dataUrl} 
              alt={`Frame at ${frame.timestamp.toFixed(2)}s`}
              className="w-full h-full object-contain"
            />
            <div className="absolute top-2 left-2 bg-black/60 backdrop-blur-md text-[10px] font-mono py-1 px-2 rounded border border-white/10">
              {frame.timestamp.toFixed(2)}s
            </div>
            <div className="absolute top-2 right-2 flex gap-1">
               {frame.isStable && (
                 <span className="bg-green-500/80 text-white text-[10px] px-1.5 py-0.5 rounded" title="Stable Frame">Stable</span>
               )}
               {frame.isUnique && (
                 <span className="bg-blue-500/80 text-white text-[10px] px-1.5 py-0.5 rounded" title="Unique Scene">Unique</span>
               )}
            </div>
          </div>

          <div className="p-3 flex items-center justify-between">
            <div className="text-xs text-gray-400">
              Score: <span className="text-gray-200">{Math.round(frame.blurScore)}</span>
            </div>
            <button 
              onClick={() => onDownload(frame)}
              className="p-1.5 bg-gray-700 hover:bg-blue-600 rounded-lg transition-colors text-white"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M7 10l5 5m0 0l5-5m-5 5V3" />
              </svg>
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

export default FrameGallery;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateBlurScore, hammingDistance } from './services/videoProcessor';
import { validateFramesWithAI } from './services/geminiService';
import FrameGallery from './components/FrameGallery';

const FRAME_INTERVAL = 1.0; // Seconds between samples
const SIMILARITY_THRESHOLD = 5; // Hamming distance (lower is more similar)
const BLUR_THRESHOLD = 300; // Arbitrary units for variance

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [progress, setProgress] = useState(0);
  const [aiAnalysis, setAiAnalysis] = useState<string[]>([]);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setFrames([]);
      setAiAnalysis([]);
      setStats({
        totalFramesAnalyzed: 0,
        duplicateCount: 0,
        blurryCount: 0,
        stableCount: 0
      });
      setStatus(ProcessingStatus.IDLE);
    }
  };

  const processVideo = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setProgress(0);

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const duration = video.duration;
    const extracted: ExtractedFrame[] = [];
    const hashes: string[] = [];

    let localStats = {
      totalFramesAnalyzed: 0,
      duplicateCount: 0,
      blurryCount: 0,
      stableCount: 0
    };

    // Helper to seek and capture
    const captureFrame = (time: number): Promise<void> => {
      return new Promise((resolve) => {
        const onSeeked = async () => {
          video.removeEventListener('seeked', onSeeked);

          // Draw to canvas
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

          const blurScore = calculateBlurScore(canvas);
          const hash = await calculateAverageHash(canvas);

          localStats.totalFramesAnalyzed++;

          // Quality filters
          const isStable = blurScore > BLUR_THRESHOLD;
          if (!isStable) {
            localStats.blurryCount++;
          } else {
            localStats.stableCount++;
          }

          // Uniqueness check
          let isUnique = true;
          for (const existingHash of hashes) {
            if (hammingDistance(hash, existingHash) < SIMILARITY_THRESHOLD) {
              isUnique = false;
              break;
            }
          }

          if (isUnique && isStable) {
            hashes.push(hash);
            extracted.push({
              id: Math.random().toString(36).substr(2, 9),
              timestamp: time,
              dataUrl: canvas.toDataURL('image/png'),
              blurScore,
              hash,
              isStable,
              isUnique
            });
          } else if (!isUnique) {
            localStats.duplicateCount++;
          }

          setStats({ ...localStats });
          setProgress(Math.min(100, (time / duration) * 100));
          resolve();
        };
        video.addEventListener('seeked', onSeeked);
        video.currentTime = time;
      });
    };

    // Iterate through video
    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await captureFrame(time);
    }

    setFrames(extracted);
    setStatus(ProcessingStatus.AI_VALIDATING);

    // AI Validation Step
    if (extracted.length > 0) {
      const analysis = await validateFramesWithAI(extracted);
      setAiAnalysis(analysis);
    }

    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const downloadFrame = (frame: ExtractedFrame) => {
    const link = document.createElement('a');
    link.download = `frame-${frame.timestamp.toFixed(2)}s.png`;
    link.href = frame.dataUrl;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
      {/* Header */}
      <header className="mb-10 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
        <div>
          <h1 className="text-4xl font-extrabold tracking-tight text-white mb-2">
            FrameMaster <span className="text-blue-500">Pro</span>
          </h1>
          <p className="text-gray-400 max-w-2xl">
            Professional-grade video frame extraction. Our engine identifies stable, unique, 
            and high-quality shots, filtering out transitions and motion blur automatically.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-6 py-3 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2">
            <svg className="w-5 h-5 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
            <span>Upload Video</span>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
          </label>

          <button 
            disabled={!videoFile || status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED}
            onClick={processVideo}
            className={`px-8 py-3 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${
              !videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed opacity-50'
                : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-500/20 active:scale-95'
            }`}
          >
            {status === ProcessingStatus.IDLE || status === ProcessingStatus.COMPLETED ? (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                <span>Extract Frames</span>
              </>
            ) : (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                <span>Processing...</span>
              </>
            )}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Processing Panel */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-6">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <svg className="w-5 h-5 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              Input Source
            </h2>

            <div className="aspect-video bg-black rounded-lg overflow-hidden border border-gray-700 relative">
              {videoUrl ? (
                <video 
                  ref={videoRef} 
                  src={videoUrl} 
                  className="w-full h-full"
                  controls
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-gray-600 text-sm">
                  No video selected
                </div>
              )}
            </div>

            <canvas ref={canvasRef} className="hidden" />

            {/* Stats Dashboard */}
            <div className="mt-8 space-y-4">
              <h3 className="text-xs font-bold uppercase tracking-wider text-gray-500">Processing Stats</h3>
              <div className="grid grid-cols-2 gap-3">
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
                  <div className="text-2xl font-bold text-blue-400">{stats.totalFramesAnalyzed}</div>
                  <div className="text-[10px] text-gray-500 uppercase">Analyzed</div>
                </div>
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
                  <div className="text-2xl font-bold text-green-400">{frames.length}</div>
                  <div className="text-[10px] text-gray-500 uppercase">Extracted</div>
                </div>
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
                  <div className="text-2xl font-bold text-yellow-400">{stats.duplicateCount}</div>
                  <div className="text-[10px] text-gray-500 uppercase">Duplicates</div>
                </div>
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
                  <div className="text-2xl font-bold text-red-400">{stats.blurryCount}</div>
                  <div className="text-[10px] text-gray-500 uppercase">Low Quality</div>
                </div>
              </div>
            </div>
          </section>

          {/* AI Feedback Panel */}
          {aiAnalysis.length > 0 && (
            <section className="bg-blue-900/10 rounded-2xl border border-blue-500/20 p-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-2 text-blue-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04M12 21.355r-.343-.133L5.618 19.16A11.955 11.955 0 013 12.039V7.818a11.955 11.955 0 018.618-3.04L12 4.773l.382-.008z" />
                </svg>
                AI Expert Validation
              </h2>
              <div className="text-sm text-blue-100/80 space-y-2 leading-relaxed italic">
                {aiAnalysis.map((text, i) => (
                  <p key={i}>{text}</p>
                ))}
              </div>
            </section>
          )}
        </div>

        {/* Results Panel */}
        <div className="lg:col-span-8">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-2xl font-bold">Extraction Results</h2>
            {status !== ProcessingStatus.IDLE && (
              <div className="flex items-center gap-3">
                <span className="text-xs font-mono text-gray-400">{Math.round(progress)}%</span>
                <div className="w-32 h-1.5 bg-gray-800 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-blue-500 transition-all duration-300"
                    style={{ width: `${progress}%` }}
                  />
                </div>
              </div>
            )}
          </div>

          <FrameGallery 
            frames={frames} 
            onDownload={downloadFrame} 
          />
        </div>
      </main>

      {/* Persistent Status Bar */}
      <footer className="fixed bottom-0 left-0 right-0 bg-gray-900/80 backdrop-blur-xl border-t border-gray-800 p-4 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 text-xs">
            <div className="flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${status === ProcessingStatus.COMPLETED ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : status === ProcessingStatus.IDLE ? 'bg-gray-600' : 'bg-blue-500 animate-pulse'}`} />
              <span className="text-gray-400 uppercase font-bold tracking-widest">{status}</span>
            </div>
            {videoFile && <span className="text-gray-500">|</span>}
            {videoFile && <span className="text-gray-400 truncate max-w-[200px]">{videoFile.name}</span>}
          </div>

          <div className="text-[10px] text-gray-500 uppercase tracking-tighter">
            Powered by Gemini 3 Flash & Intelligent Frame Sampling
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { ExtractedFrame } from '../types';

interface FrameGalleryProps {
  frames: ExtractedFrame[];
  selectedIds: Set<string>;
  onToggleSelection: (id: string) => void;
  onToggleAll: (selected: boolean) => void;
  onDownload: (frame: ExtractedFrame) => void;
}

const FrameGallery: React.FC<FrameGalleryProps> = ({ 
  frames, 
  selectedIds, 
  onToggleSelection, 
  onToggleAll,
  onDownload 
}) => {
  if (frames.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-12 bg-gray-900/50 rounded-2xl border border-dashed border-gray-700">
        <svg className="w-16 h-16 text-gray-600 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
        <p className="text-gray-400">No frames extracted yet. Upload a video and start processing.</p>
      </div>
    );
  }

  const allSelected = frames.length > 0 && selectedIds.size === frames.length;

  return (
    <div className="space-y-6">
      {/* Bulk Action Bar */}
      <div className="flex items-center gap-4 py-3 px-4 bg-gray-900/80 backdrop-blur rounded-xl border border-gray-800 sticky top-0 z-10 shadow-lg">
        <label className="flex items-center gap-3 cursor-pointer group">
          <div className="relative flex items-center">
            <input 
              type="checkbox" 
              checked={allSelected}
              onChange={(e) => onToggleAll(e.target.checked)}
              className="peer appearance-none w-5 h-5 border-2 border-gray-600 rounded checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
            />
            <svg className="absolute w-3.5 h-3.5 text-white left-0.5 pointer-events-none opacity-0 peer-checked:opacity-100 transition-opacity" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <span className="text-sm font-medium text-gray-300 group-hover:text-white transition-colors">
            {allSelected ? 'Deselect All' : 'Select All'} ({selectedIds.size} of {frames.length})
          </span>
        </label>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {frames.map((frame) => {
          const isSelected = selectedIds.has(frame.id);
          return (
            <div 
              key={frame.id} 
              onClick={() => onToggleSelection(frame.id)}
              className={`group relative bg-gray-800 rounded-xl overflow-hidden border transition-all shadow-lg cursor-pointer ${
                isSelected ? 'border-blue-500 ring-2 ring-blue-500/20' : 'border-gray-700 hover:border-gray-500'
              }`}
            >
              <div className="aspect-video bg-black relative">
                <img 
                  src={frame.dataUrl} 
                  alt={`Frame at ${frame.timestamp.toFixed(2)}s`}
                  className={`w-full h-full object-contain transition-transform duration-300 ${isSelected ? 'scale-105' : 'group-hover:scale-102'}`}
                />

                {/* Selection Overlay */}
                <div className={`absolute inset-0 bg-blue-600/10 transition-opacity ${isSelected ? 'opacity-100' : 'opacity-0'}`} />

                {/* Checkbox Indicator */}
                <div className={`absolute top-3 left-3 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                  isSelected ? 'bg-blue-600 border-blue-600 shadow-md' : 'bg-black/40 border-white/40 backdrop-blur-sm'
                }`}>
                   {isSelected && (
                     <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                       <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                     </svg>
