                <div className="absolute bottom-2 left-2 bg-black/60 backdrop-blur-md text-[10px] font-mono py-1 px-2 rounded border border-white/10">
                  {frame.timestamp.toFixed(2)}s
                </div>

                <div className="absolute top-2 right-2 flex gap-1">
                   {frame.isStable && (
                     <span className="bg-green-500/80 text-white text-[10px] px-1.5 py-0.5 rounded shadow-sm" title="Stable Frame">Stable</span>
                   )}
                   {frame.isUnique && (
                     <span className="bg-blue-500/80 text-white text-[10px] px-1.5 py-0.5 rounded shadow-sm" title="Unique Scene">Unique</span>
                   )}
                </div>
              </div>

              <div className="p-3 flex items-center justify-between bg-gray-800/50 backdrop-blur-sm border-t border-gray-700/50">
                <div className="text-xs text-gray-400">
                  Quality Score: <span className="text-gray-200 font-medium">{Math.round(frame.blurScore)}</span>
                </div>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onDownload(frame);
                  }}
                  className="p-1.5 bg-gray-700 hover:bg-blue-600 rounded-lg transition-colors text-white shadow-sm"
                  title="Download individually"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M7 10l5 5m0 0l5-5m-5 5V3" />
                  </svg>
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

