import React, { useState, useRef, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { ProcessingStatus, ExtractedFrame, ProcessingStats } from './types';
import { calculateAverageHash, calculateBlurScore, hammingDistance } from './services/videoProcessor';
import { validateFramesWithAI } from './services/geminiService';
import FrameGallery from './components/FrameGallery';

const FRAME_INTERVAL = 1.0; // Seconds between samples
const SIMILARITY_THRESHOLD = 5; // Hamming distance (lower is more similar)
const BLUR_THRESHOLD = 300; // Arbitrary units for variance

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [frames, setFrames] = useState<ExtractedFrame[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [progress, setProgress] = useState(0);
  const [aiAnalysis, setAiAnalysis] = useState<string[]>([]);
  const [isDownloading, setIsDownloading] = useState(false);
  const [stats, setStats] = useState<ProcessingStats>({
    totalFramesAnalyzed: 0,
    duplicateCount: 0,
    blurryCount: 0,
    stableCount: 0
  });

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setFrames([]);
      setSelectedIds(new Set());
      setAiAnalysis([]);
      setStats({
        totalFramesAnalyzed: 0,
        duplicateCount: 0,
        blurryCount: 0,
        stableCount: 0
      });
      setStatus(ProcessingStatus.IDLE);
    }
  };

  const processVideo = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setStatus(ProcessingStatus.EXTRACTING);
    setFrames([]);
    setSelectedIds(new Set());
    setProgress(0);

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const duration = video.duration;
    const extracted: ExtractedFrame[] = [];
    const hashes: string[] = [];

    let localStats = {
      totalFramesAnalyzed: 0,
      duplicateCount: 0,
      blurryCount: 0,
      stableCount: 0
    };

    const captureFrame = (time: number): Promise<void> => {
      return new Promise((resolve) => {
        const onSeeked = async () => {
          video.removeEventListener('seeked', onSeeked);

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

          const blurScore = calculateBlurScore(canvas);
          const hash = await calculateAverageHash(canvas);

          localStats.totalFramesAnalyzed++;

          const isStable = blurScore > BLUR_THRESHOLD;
          if (!isStable) {
            localStats.blurryCount++;
          } else {
            localStats.stableCount++;
          }

          let isUnique = true;
          for (const existingHash of hashes) {
            if (hammingDistance(hash, existingHash) < SIMILARITY_THRESHOLD) {
              isUnique = false;
              break;
            }
          }

          if (isUnique && isStable) {
            hashes.push(hash);
            extracted.push({
              id: Math.random().toString(36).substr(2, 9),
              timestamp: time,
              dataUrl: canvas.toDataURL('image/png'),
              blurScore,
              hash,
              isStable,
              isUnique
            });
          } else if (!isUnique) {
            localStats.duplicateCount++;
          }

          setStats({ ...localStats });
          setProgress(Math.min(100, (time / duration) * 100));
          resolve();
        };
        video.addEventListener('seeked', onSeeked);
        video.currentTime = time;
      });
    };

    for (let time = 0; time < duration; time += FRAME_INTERVAL) {
      await captureFrame(time);
    }

    setFrames(extracted);
    // Auto-select all frames by default
    setSelectedIds(new Set(extracted.map(f => f.id)));
    setStatus(ProcessingStatus.AI_VALIDATING);

    if (extracted.length > 0) {
      const analysis = await validateFramesWithAI(extracted);
      setAiAnalysis(analysis);
    }

    setStatus(ProcessingStatus.COMPLETED);
    setProgress(100);
  };

  const toggleFrameSelection = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const toggleAllSelection = (selected: boolean) => {
    if (selected) {
      setSelectedIds(new Set(frames.map(f => f.id)));
    } else {
      setSelectedIds(new Set());
    }
  };

  const downloadFrame = (frame: ExtractedFrame) => {
    const link = document.createElement('a');
    link.download = `frame-${frame.timestamp.toFixed(2)}s.png`;
    link.href = frame.dataUrl;
    link.click();
  };

  const downloadSelected = async () => {
    if (selectedIds.size === 0) return;
    setIsDownloading(true);

    try {
      const zip = new JSZip();
      const selectedFrames = frames.filter(f => selectedIds.has(f.id));

      for (const frame of selectedFrames) {
        // Remove the data URI prefix (e.g., "data:image/png;base64,")
        const base64Data = frame.dataUrl.split(',')[1];
        zip.file(`frame-${frame.timestamp.toFixed(2)}s.png`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `framemaster-pro-export-${new Date().getTime()}.zip`;
      link.click();
    } catch (error) {
      console.error("Download Error:", error);
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
      {/* Header */}
      <header className="mb-10 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
        <div>
          <h1 className="text-4xl font-extrabold tracking-tight text-white mb-2">
            FrameMaster <span className="text-blue-500">Pro</span>
          </h1>
          <p className="text-gray-400 max-w-2xl">
            Professional-grade video frame extraction. Our engine identifies stable, unique, 
            and high-quality shots, filtering out transitions and motion blur automatically.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <label className="cursor-pointer bg-gray-800 hover:bg-gray-700 text-white px-6 py-3 rounded-xl border border-gray-700 transition-all flex items-center justify-center gap-2">
            <svg className="w-5 h-5 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
            <span>Upload Video</span>
            <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
          </label>

          <button 
            disabled={!videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)}
            onClick={processVideo}
            className={`px-8 py-3 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${
              !videoFile || (status !== ProcessingStatus.IDLE && status !== ProcessingStatus.COMPLETED)
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed opacity-50'
                : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-500/20 active:scale-95'
            }`}
          >
            {status === ProcessingStatus.IDLE || status === ProcessingStatus.COMPLETED ? (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                <span>Extract Frames</span>
              </>
            ) : (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                <span>Processing...</span>
              </>
            )}
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 mb-24">
        {/* Processing Panel */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-gray-900/50 rounded-2xl border border-gray-800 p-6 shadow-xl">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <svg className="w-5 h-5 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              Input Source
            </h2>

            <div className="aspect-video bg-black rounded-lg overflow-hidden border border-gray-700 relative">
              {videoUrl ? (
                <video 
                  ref={videoRef} 
                  src={videoUrl} 
                  className="w-full h-full"
                  controls
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-gray-600 text-sm italic">
                  No video selected
                </div>
              )}
