  duplicateCount: number;
  blurryCount: number;
  stableCount: number;
  revealCount: number;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  EXTRACTING = 'EXTRACTING',
  ANALYZING = 'ANALYZING',
  AI_VALIDATING = 'AI_VALIDATING',
  COMPLETED = 'COMPLETED',
