                >
                  {isDownloading ? (
                    <>
                      <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                      <span>Creating ZIP...</span>
                    </>
                  ) : (
                    <>
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M7 10l5 5m0 0l5-5m-5 5V3" />
                      </svg>
                      <span>Download {selectedIds.size} Selected</span>
                    </>
                  )}
                </button>
              )}
            </div>
          </div>

          <FrameGallery 
            frames={frames} 
            selectedIds={selectedIds}
            onToggleSelection={toggleFrameSelection}
            onToggleAll={toggleAllSelection}
            onDownload={downloadFrame} 
