        </div>
      </main>

      {/* Persistent Status Bar */}
      <footer className="fixed bottom-0 left-0 right-0 bg-gray-900/80 backdrop-blur-xl border-t border-gray-800 p-4 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4 text-xs">
            <div className="flex items-center gap-2">
              <span className={`w-2.5 h-2.5 rounded-full ${status === ProcessingStatus.COMPLETED ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : status === ProcessingStatus.IDLE ? 'bg-gray-600' : 'bg-blue-500 animate-pulse'}`} />
              <span className="text-gray-400 uppercase font-bold tracking-widest">{status === ProcessingStatus.AI_VALIDATING ? 'AI Audit In Progress' : status}</span>
