export interface ExtractedFrame {
  id: string;
  timestamp: number;
  dataUrl: string;
  blurScore: number;
  hash: string;
  isStable: boolean;
  isUnique: boolean;
  isReveal?: boolean; // True if captured due to detecting a content reveal (e.g. scroll)
  aiFeedback?: string;
}

export interface ProcessingStats {
  totalFramesAnalyzed: number;
  duplicateCount: number;
  blurryCount: number;
  stableCount: number;
  revealCount: number;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  EXTRACTING = 'EXTRACTING',
  ANALYZING = 'ANALYZING',
  AI_VALIDATING = 'AI_VALIDATING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { ExtractedFrame } from '../types';

/**
 * Calculates the percentage of pixels that have changed between two canvases.
 * Used to detect scrolling, significant motion, or scene reveals.
 */
export function calculatePixelChange(canvas1: HTMLCanvasElement, canvas2: HTMLCanvasElement): number {
  if (canvas1.width !== canvas2.width || canvas1.height !== canvas2.height) return 100;

  const ctx1 = canvas1.getContext('2d', { willReadFrequently: true });
  const ctx2 = canvas2.getContext('2d', { willReadFrequently: true });
  if (!ctx1 || !ctx2) return 0;

  const data1 = ctx1.getImageData(0, 0, canvas1.width, canvas1.height).data;
  const data2 = ctx2.getImageData(0, 0, canvas2.width, canvas2.height).data;

  let diffCount = 0;
  const step = 40; // Sample every 10th pixel (4 channels per pixel)
  let totalSampled = 0;

  for (let i = 0; i < data1.length; i += step) {
    totalSampled++;
    const rDiff = Math.abs(data1[i] - data2[i]);
    const gDiff = Math.abs(data1[i+1] - data2[i+1]);
    const bDiff = Math.abs(data1[i+2] - data2[i+2]);

    // Threshold for a "changed" pixel
    if ((rDiff + gDiff + bDiff) / 3 > 30) {
      diffCount++;
    }
  }

  return (diffCount / totalSampled) * 100;
}

/**
 * Calculates a simple average hash (8x8) of a canvas for uniqueness detection.
 */
export async function calculateAverageHash(canvas: HTMLCanvasElement): Promise<string> {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return '';

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 8;
  tempCanvas.height = 8;
  const tempCtx = tempCanvas.getContext('2d');
  if (!tempCtx) return '';

  tempCtx.drawImage(canvas, 0, 0, 8, 8);
  const imageData = tempCtx.getImageData(0, 0, 8, 8);
  const pixels = imageData.data;

  let sum = 0;
  const grayscale = new Uint8Array(64);
  for (let i = 0; i < 64; i++) {
    const r = pixels[i * 4];
    const g = pixels[i * 4 + 1];
    const b = pixels[i * 4 + 2];
    const gray = (r + g + b) / 3;
    grayscale[i] = gray;
    sum += gray;
  }
  const avg = sum / 64;

  let hash = '';
  for (let i = 0; i < 64; i++) {
    hash += grayscale[i] >= avg ? '1' : '0';
  }
  return hash;
}

/**
 * Calculates a simple blur score based on variance of intensity changes.
 */
export function calculateBlurScore(canvas: HTMLCanvasElement): number {
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return 0;

  const width = canvas.width;
  const height = canvas.height;
  const imageData = ctx.getImageData(0, 0, width, height);
  const data = imageData.data;

  let mean = 0;
  const values: number[] = [];
  for (let i = 0; i < data.length; i += 40) {
    const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
    values.push(gray);
    mean += gray;
  }
  mean /= values.length;

  let variance = 0;
  for (const v of values) {
    variance += (v - mean) * (v - mean);
  }
  variance /= values.length;

  return variance;
}

/**
 * Compares two hashes using Hamming Distance.
 */
export function hammingDistance(h1: string, h2: string): number {
  let distance = 0;
  for (let i = 0; i < h1.length; i++) {
    if (h1[i] !== h2[i]) distance++;
  }
  return distance;
}

