                  <div className="text-[10px] text-gray-500 uppercase font-semibold">Valid</div>
                </div>
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
                  <div className="text-2xl font-bold text-purple-400">{stats.revealCount}</div>
                  <div className="text-[10px] text-gray-500 uppercase font-semibold">Reveals</div>
                </div>
                <div className="bg-gray-800/50 p-3 rounded-xl border border-gray-700/50">
